import{_ as e,o as d,c as o,ag as t}from"./chunks/framework-C5-Jzrz4.js";const c=JSON.parse('{"title":"Common UI 组件集","description":"@vben/common-ui 的公开导出、模块分组与接入关系","frontmatter":{"title":"Common UI 组件集","description":"@vben/common-ui 的公开导出、模块分组与接入关系","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"scripts/components/common-ui/vben-common-ui.md","filePath":"scripts/components/common-ui/vben-common-ui.md","lastUpdated":null}');const r=e({name:"scripts/components/common-ui/vben-common-ui.md"},[["render",function(e,c,r,n,a,i){return d(),o("div",null,[...c[0]||(c[0]=[t('<h1 id="vben-common-ui" tabindex="-1"><code>@vben/common-ui</code> <a class="header-anchor" href="#vben-common-ui" aria-label="Permalink to &quot;`@vben/common-ui`&quot;">​</a></h1><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><ul><li>包名：<code>@vben/common-ui</code></li><li>所属目录：<code>packages/effects/common-ui</code></li><li>公开入口： <ul><li><code>@vben/common-ui</code></li><li><code>@vben/common-ui/es/loading</code></li><li><code>@vben/common-ui/es/tippy</code></li></ul></li></ul><p>该包是当前仓库中“最上层”的通用组件聚合入口。它并不只包含自身目录下的组件，还二次导出了 <code>@vben-core/form-ui</code>、<code>@vben-core/popup-ui</code> 以及部分 <code>@vben-core/shadcn-ui</code> 组件。</p><h2 id="导出结构" tabindex="-1">导出结构 <a class="header-anchor" href="#导出结构" aria-label="Permalink to &quot;导出结构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>导出入口</th><th>源码位置</th><th>说明</th></tr></thead><tbody><tr><td><code>@vben/common-ui</code></td><td><code>packages/effects/common-ui/src/index.ts</code></td><td>聚合 <code>components/</code>、<code>ui/</code>、表单、弹窗与部分基础 UI</td></tr><tr><td><code>@vben/common-ui/es/loading</code></td><td><code>packages/effects/common-ui/src/components/loading/index.ts</code></td><td><code>Loading</code>、<code>Spinner</code>、<code>registerLoadingDirective</code></td></tr><tr><td><code>@vben/common-ui/es/tippy</code></td><td><code>packages/effects/common-ui/src/components/tippy/index.ts</code></td><td><code>Tippy</code>、<code>initTippy</code>、<code>TippyProps</code></td></tr></tbody></table><h2 id="components-导出模块" tabindex="-1"><code>components/</code> 导出模块 <a class="header-anchor" href="#components-导出模块" aria-label="Permalink to &quot;`components/` 导出模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块/导出名</th><th>源码目录</th><th>说明</th></tr></thead><tbody><tr><td><code>ApiComponent</code></td><td><code>src/components/api-component</code></td><td>基于接口数据驱动的组件封装</td></tr><tr><td><code>PointSelectionCaptcha</code>、<code>PointSelectionCaptchaCard</code>、<code>SliderCaptcha</code>、<code>SliderRotateCaptcha</code>、<code>SliderTranslateCaptcha</code></td><td><code>src/components/captcha</code></td><td>点选、滑块、旋转、拼图验证码组件</td></tr><tr><td><code>CodeMirror</code>、<code>LanguageSupport</code></td><td><code>src/components/code-mirror</code></td><td>代码预览/编辑能力</td></tr><tr><td><code>ColPage</code></td><td><code>src/components/col-page</code></td><td>左右分栏页面容器，继承 <code>PageProps</code></td></tr><tr><td><code>CountTo</code></td><td><code>src/components/count-to</code></td><td>数字递增动画组件</td></tr><tr><td><code>VCropper</code></td><td><code>src/components/cropper</code></td><td>图片裁剪组件</td></tr><tr><td><code>EllipsisText</code></td><td><code>src/components/ellipsis-text</code></td><td>省略文本展示</td></tr><tr><td><code>IconPicker</code></td><td><code>src/components/icon-picker</code></td><td>图标选择器</td></tr><tr><td><code>JsonPreview</code></td><td><code>src/components/json-preview</code></td><td>JSON 预览组件</td></tr><tr><td><code>JsonViewer</code></td><td><code>src/components/json-viewer</code></td><td>JSON 树形查看组件</td></tr><tr><td><code>Loading</code>、<code>Spinner</code>、<code>registerLoadingDirective</code></td><td><code>src/components/loading</code></td><td>加载组件与 <code>v-loading</code> 指令</td></tr><tr><td><code>MarkdownEditor</code>、<code>MarkdownPreviewer</code></td><td><code>src/components/markdown</code></td><td>Markdown 编辑与预览</td></tr><tr><td><code>Page</code></td><td><code>src/components/page</code></td><td>页面级布局容器</td></tr><tr><td><code>VResize</code></td><td><code>src/components/resize</code></td><td>尺寸变化监听组件</td></tr><tr><td><code>Tippy</code>、<code>initTippy</code>、<code>TippyProps</code></td><td><code>src/components/tippy</code></td><td>Tooltip/Popover 指令与组件封装</td></tr><tr><td><code>Tree</code></td><td><code>src/components/tree</code></td><td>树组件</td></tr><tr><td><code>export * from &#39;@vben-core/form-ui&#39;</code></td><td><code>src/components/index.ts</code></td><td>直接复用 <code>useVbenForm</code>、<code>setupVbenForm</code>、<code>VbenFormSchema</code> 等表单能力</td></tr><tr><td><code>export * from &#39;@vben-core/popup-ui&#39;</code></td><td><code>src/components/index.ts</code></td><td>直接复用 <code>useVbenModal</code>、<code>useVbenDrawer</code>、弹窗组件与 API</td></tr><tr><td><code>VbenAvatar</code>、<code>VbenButton</code>、<code>VbenButtonGroup</code>、<code>VbenCheckbox</code>、<code>VbenCheckButtonGroup</code>、<code>VbenContextMenu</code>、<code>VbenCountToAnimator</code>、<code>VbenFullScreen</code>、<code>VbenInputPassword</code>、<code>VbenLoading</code>、<code>VbenLogo</code>、<code>VbenPinInput</code>、<code>VbenSelect</code>、<code>VbenSpinner</code></td><td><code>src/components/index.ts</code></td><td>从 <code>@vben-core/shadcn-ui</code> 二次导出的基础 UI 组件</td></tr></tbody></table><h2 id="ui-场景模块" tabindex="-1"><code>ui/</code> 场景模块 <a class="header-anchor" href="#ui-场景模块" aria-label="Permalink to &quot;`ui/` 场景模块&quot;">​</a></h2><p>场景页面能力已单独整理为 <a href="./scene-ui">Scene UI 场景页面</a>。这里仅保留根包与子路径的聚合关系。</p><table tabindex="0"><thead><tr><th>导出名</th><th>源码目录</th><th>说明</th></tr></thead><tbody><tr><td><code>About</code></td><td><code>src/ui/about</code></td><td>关于页组件</td></tr><tr><td><code>AuthenticationLogin</code>、<code>AuthenticationCodeLogin</code>、<code>AuthenticationForgetPassword</code>、<code>AuthenticationQrCodeLogin</code>、<code>AuthenticationRegister</code>、<code>AuthenticationLoginExpiredModal</code></td><td><code>src/ui/authentication</code></td><td>登录、验证码登录、忘记密码、二维码登录、注册、登录过期弹窗</td></tr><tr><td><code>AnalysisChartCard</code>、<code>AnalysisChartsTabs</code>、<code>AnalysisOverview</code></td><td><code>src/ui/dashboard/analysis</code></td><td>分析页卡片与图表区块</td></tr><tr><td><code>WorkbenchHeader</code>、<code>WorkbenchProject</code>、<code>WorkbenchQuickNav</code>、<code>WorkbenchTodo</code>、<code>WorkbenchTrends</code></td><td><code>src/ui/dashboard/workbench</code></td><td>工作台场景组件</td></tr><tr><td><code>Fallback</code></td><td><code>src/ui/fallback</code></td><td>403/404/500/离线/Coming Soon 等兜底页</td></tr><tr><td><code>Profile</code>、<code>ProfileBaseSetting</code>、<code>ProfileNotificationSetting</code>、<code>ProfilePasswordSetting</code>、<code>ProfileSecuritySetting</code></td><td><code>src/ui/profile</code></td><td>个人中心场景组件</td></tr></tbody></table><h2 id="核心-api-线索" tabindex="-1">核心 API 线索 <a class="header-anchor" href="#核心-api-线索" aria-label="Permalink to &quot;核心 API 线索&quot;">​</a></h2><h3 id="已在类型文件中声明的-api" tabindex="-1">已在类型文件中声明的 API <a class="header-anchor" href="#已在类型文件中声明的-api" aria-label="Permalink to &quot;已在类型文件中声明的 API&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>源码位置</th><th>关键内容</th></tr></thead><tbody><tr><td><code>AuthenticationProps</code></td><td><code>src/ui/authentication/types.ts</code></td><td>控制登录页标题、按钮、是否显示验证码登录/注册/二维码登录/第三方登录</td></tr><tr><td><code>GrantType</code>、<code>LoginAndRegisterParams</code>、<code>LoginCodeParams</code></td><td><code>src/ui/authentication/types.ts</code></td><td>登录/注册表单提交数据结构</td></tr><tr><td><code>PageProps</code></td><td><code>src/components/page/types.ts</code></td><td><code>title</code>、<code>description</code>、<code>autoContentHeight</code>、<code>heightOffset</code> 等</td></tr><tr><td><code>ColPageProps</code></td><td><code>src/components/col-page/types.ts</code></td><td>在 <code>PageProps</code> 基础上补充左右栏宽度、可折叠、可拖拽等</td></tr><tr><td><code>PointSelectionCaptchaProps</code>、<code>SliderCaptchaProps</code>、<code>SliderRotateCaptchaProps</code>、<code>SliderTranslateCaptchaProps</code></td><td><code>src/components/captcha/types.ts</code></td><td>验证码模块公开 props</td></tr><tr><td><code>LanguageSupport</code></td><td><code>src/components/code-mirror/data.ts</code></td><td>CodeMirror 语言支持类型</td></tr></tbody></table><h3 id="未在统一入口中声明的内容" tabindex="-1">未在统一入口中声明的内容 <a class="header-anchor" href="#未在统一入口中声明的内容" aria-label="Permalink to &quot;未在统一入口中声明的内容&quot;">​</a></h3><ul><li><code>@vben/common-ui</code> 没有为所有子模块建立统一的 props/events/slots 类型表。</li><li>某些导出只有默认组件，没有配套 <code>types.ts</code>，此时应以对应目录的 <code>.vue</code> 实现为准。</li><li><code>PointSelectionCaptchaCard</code> 当前与 <code>PointSelectionCaptcha</code> 指向同一个 <code>index.vue</code> 默认导出，源码中未发现独立卡片组件入口。</li></ul><h2 id="依赖与适配关系" tabindex="-1">依赖与适配关系 <a class="header-anchor" href="#依赖与适配关系" aria-label="Permalink to &quot;依赖与适配关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关系</th><th>说明</th></tr></thead><tbody><tr><td>依赖 <code>@vben-core/form-ui</code></td><td>统一承接表单 schema、<code>useVbenForm</code>、校验能力</td></tr><tr><td>依赖 <code>@vben-core/popup-ui</code></td><td>统一承接 <code>useVbenModal</code> / <code>useVbenDrawer</code></td></tr><tr><td>依赖 <code>@vben-core/shadcn-ui</code></td><td>复用头像、按钮、下拉、全屏、上下文菜单等基础 UI</td></tr><tr><td>依赖 <code>@vben/preferences</code>、<code>@vben/locales</code></td><td>驱动主题、语言与用户可见文本</td></tr><tr><td>依赖 <code>vue-tippy</code></td><td><code>Tippy</code> 指令与组件封装</td></tr></tbody></table><h2 id="仓库中的实际使用场景" tabindex="-1">仓库中的实际使用场景 <a class="header-anchor" href="#仓库中的实际使用场景" aria-label="Permalink to &quot;仓库中的实际使用场景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>使用位置</th><th>实际调用</th></tr></thead><tbody><tr><td><code>apps/web-antd/src/bootstrap.ts</code></td><td><code>setDefaultModalProps</code>、<code>registerLoadingDirective</code>、<code>initTippy</code></td></tr><tr><td><code>apps/web-antd/src/adapter/form.ts</code></td><td><code>setupVbenForm</code>、<code>useVbenForm</code>、<code>z</code></td></tr><tr><td><code>apps/web-antd/src/layouts/basic.vue</code></td><td><code>AuthenticationLoginExpiredModal</code></td></tr><tr><td><code>apps/web-antd/src/views/_core/authentication/*</code></td><td><code>AuthenticationLogin</code>、<code>AuthenticationCodeLogin</code>、<code>AuthenticationRegister</code> 等</td></tr><tr><td><code>apps/web-antd/src/views/dashboard/*</code></td><td><code>AnalysisOverview</code>、<code>WorkbenchHeader</code> 等</td></tr><tr><td><code>apps/web-antd/src/views/system/*</code>、<code>apps/web-antd/src/views/workflow/*</code></td><td><code>Page</code>、<code>useVbenModal</code>、<code>useVbenDrawer</code>、<code>JsonPreview</code>、<code>CodeMirror</code> 等</td></tr></tbody></table><h2 id="本次补充索引" tabindex="-1">本次补充索引 <a class="header-anchor" href="#本次补充索引" aria-label="Permalink to &quot;本次补充索引&quot;">​</a></h2><p>下面这些入口是仓库里已经在业务中直接使用、并且本次补了可运行示例的文档页：</p><table tabindex="0"><thead><tr><th>实际入口</th><th>典型业务</th><th>详细文档</th></tr></thead><tbody><tr><td><code>Page</code></td><td>列表页、详情页</td><td><a href="./page">page.md</a></td></tr><tr><td><code>useVbenForm</code> / <code>setupVbenForm</code></td><td>登录、抽屉、个人设置</td><td><a href="./vben-form">vben-form.md</a></td></tr><tr><td><code>useVbenModal</code></td><td>详情弹窗、导入弹窗、代码预览</td><td><a href="./vben-modal">vben-modal.md</a></td></tr><tr><td><code>useVbenDrawer</code></td><td>编辑抽屉、详情抽屉</td><td><a href="./vben-drawer">vben-drawer.md</a></td></tr><tr><td><code>ApiComponent</code></td><td>远程下拉、树选择</td><td><a href="./vben-api-component">vben-api-component.md</a></td></tr><tr><td><code>IconPicker</code></td><td>菜单/表单图标选择</td><td><a href="./icon-picker">icon-picker.md</a></td></tr><tr><td><code>JsonPreview</code></td><td>流程变量、配置详情</td><td><a href="./json-preview">json-preview.md</a></td></tr><tr><td><code>CodeMirror</code></td><td>代码预览、模板展示</td><td><a href="./code-mirror">code-mirror.md</a></td></tr><tr><td><code>Loading</code></td><td>路由加载、局部遮罩</td><td><a href="./loading">loading.md</a></td></tr><tr><td><code>Tippy</code></td><td>图标提示、按钮说明</td><td><a href="./tippy">tippy.md</a></td></tr><tr><td><code>VbenCountToAnimator</code></td><td>仪表盘数字动画</td><td><a href="./vben-count-to-animator">vben-count-to-animator.md</a></td></tr><tr><td><code>Authentication*</code>、<code>Analysis*</code>、<code>Workbench*</code>、<code>Profile*</code>、<code>Fallback</code>、<code>About</code></td><td>场景页</td><td><a href="./scene-ui">scene-ui.md</a></td></tr><tr><td><code>VbenAvatar</code>、<code>VbenButton</code>、<code>VbenCheckbox</code>、<code>VbenContextMenu</code>、<code>VbenCountToAnimator</code>、<code>VbenFullScreen</code>、<code>VbenInputPassword</code>、<code>VbenLoading</code>、<code>VbenLogo</code>、<code>VbenPinInput</code>、<code>VbenSelect</code>、<code>VbenSpinner</code> 等</td><td>基础 UI / 数字动画</td><td><a href="./shadcn-ui">shadcn-ui.md</a></td></tr></tbody></table><h2 id="本次未展开的入口" tabindex="-1">本次未展开的入口 <a class="header-anchor" href="#本次未展开的入口" aria-label="Permalink to &quot;本次未展开的入口&quot;">​</a></h2><p>这些导出在包内存在，但在 <code>apps/web-antd</code> 里未检出稳定的业务侧直接引用，所以本轮没有补业务示例：</p><ul><li><code>PointSelectionCaptcha</code>、<code>PointSelectionCaptchaCard</code>、<code>SliderCaptcha</code>、<code>SliderRotateCaptcha</code>、<code>SliderTranslateCaptcha</code></li><li><code>ColPage</code></li><li><code>VCropper</code></li><li><code>EllipsisText</code></li><li><code>JsonViewer</code></li><li><code>MarkdownEditor</code>、<code>MarkdownPreviewer</code></li><li><code>VResize</code></li><li><code>Tree</code></li></ul><h2 id="使用注意事项" tabindex="-1">使用注意事项 <a class="header-anchor" href="#使用注意事项" aria-label="Permalink to &quot;使用注意事项&quot;">​</a></h2><ul><li>该包是“聚合入口”，不代表所有 API 都在这一层定义。查 props 和事件时要继续追到子目录。</li><li>如果只需要 <code>Loading</code> 或 <code>Tippy</code>，仓库已经提供了明确的子路径导出，优先使用 <code>@vben/common-ui/es/loading</code> 和 <code>@vben/common-ui/es/tippy</code>。</li><li>表单、弹窗的核心能力并不在本包内实现，而是转发到 <code>@vben-core/form-ui</code> 与 <code>@vben-core/popup-ui</code>。</li></ul>',28)])])}]]);export{c as __pageData,r as default};
